//! Core performance benchmarks for netspeed-cli.
//!
//! Benchmarks critical pure functions in:
//! - Bandwidth calculation (`common::calculate_bandwidth`)
//! - Distance calculation (`servers::calculate_distance`)
//! - Formatting utilities (`common::format_distance`, `common::format_data_size`)
//! - IP validation (`common::is_valid_ipv4`)
//! - URL construction (`download::build_test_url`, `upload::build_upload_url`)

#![allow(clippy::wildcard_imports)]

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use netspeed_cli::common;

mod bandwidth {
    use super::*;

    pub fn bench_calculate_bandwidth(c: &mut Criterion) {
        let mut group = c.benchmark_group("bandwidth/calculate_bandwidth");

        for (bytes, elapsed) in [
            (1_000_000u64, 0.1f64),
            (10_000_000u64, 1.0f64),
            (100_000_000u64, 10.0f64),
            (1_000_000_000u64, 100.0f64),
        ] {
            group.bench_with_input(
                BenchmarkId::from_parameter(format!("{bytes}B/{elapsed}s")),
                &(bytes, elapsed),
                |b, &(bytes, elapsed)| {
                    b.iter(|| {
                        common::calculate_bandwidth(
                            std::hint::black_box(bytes),
                            std::hint::black_box(elapsed),
                        )
                    });
                },
            );
        }

        group.finish();
    }

    pub fn bench_calculate_bandwidth_zero_elapsed(c: &mut Criterion) {
        c.bench_function("bandwidth/zero_elapsed", |b| {
            b.iter(|| {
                common::calculate_bandwidth(
                    std::hint::black_box(1_000_000u64),
                    std::hint::black_box(0.0f64),
                )
            });
        });
    }
}

mod distance {
    use super::*;

    pub fn bench_calculate_distance(c: &mut Criterion) {
        let mut group = c.benchmark_group("distance/calculate_distance");

        let routes = [
            ("NYC-LA", 40.7128f64, -74.0060f64, 34.0522f64, -118.2437f64),
            (
                "NYC-London",
                40.7128f64,
                -74.0060f64,
                51.5074f64,
                -0.1278f64,
            ),
            (
                "Tokyo-Sydney",
                35.6762f64,
                139.6503f64,
                -33.8688f64,
                151.2093f64,
            ),
            (
                "Same location",
                40.7128f64,
                -74.0060f64,
                40.7128f64,
                -74.0060f64,
            ),
        ];

        for (name, lat1, lon1, lat2, lon2) in routes {
            group.bench_with_input(
                BenchmarkId::from_parameter(name),
                &(lat1, lon1, lat2, lon2),
                |b, &(lat1, lon1, lat2, lon2)| {
                    b.iter(|| {
                        netspeed_cli::servers::calculate_distance(
                            std::hint::black_box(lat1),
                            std::hint::black_box(lon1),
                            std::hint::black_box(lat2),
                            std::hint::black_box(lon2),
                        )
                    });
                },
            );
        }

        group.finish();
    }
}

mod formatting {
    use super::*;

    pub fn bench_format_distance(c: &mut Criterion) {
        let mut group = c.benchmark_group("formatting/format_distance");

        for (value, label) in [
            (12.5f64, "short"),
            (99.9f64, "boundary"),
            (150.5f64, "medium"),
            (5570.0f64, "long"),
        ] {
            group.bench_with_input(BenchmarkId::from_parameter(label), &value, |b, &value| {
                b.iter(|| common::format_distance(std::hint::black_box(value)));
            });
        }

        group.finish();
    }

    pub fn bench_format_data_size(c: &mut Criterion) {
        let mut group = c.benchmark_group("formatting/format_data_size");

        for (bytes, label) in [
            (512u64, "bytes"),
            (500 * 1024, "kilobytes"),
            (10 * 1024 * 1024, "megabytes"),
            (4 * 1024 * 1024 * 1024, "gigabytes"),
        ] {
            group.bench_with_input(BenchmarkId::from_parameter(label), &bytes, |b, &bytes| {
                b.iter(|| common::format_data_size(std::hint::black_box(bytes)));
            });
        }

        group.finish();
    }
}

mod validation {
    use super::*;

    pub fn bench_is_valid_ipv4(c: &mut Criterion) {
        let mut group = c.benchmark_group("validation/is_valid_ipv4");

        for (ip, label) in [
            ("192.168.1.1", "valid"),
            ("10.0.0.1", "valid_private"),
            ("255.255.255.255", "broadcast"),
            ("999.999.999.999", "invalid_octets"),
            ("1.2.3", "too_few"),
            ("1.2.3.4.5", "too_many"),
            ("abc", "not_ip"),
        ] {
            group.bench_with_input(BenchmarkId::from_parameter(label), &ip, |b, &ip| {
                b.iter(|| common::is_valid_ipv4(std::hint::black_box(ip)));
            });
        }

        group.finish();
    }
}

mod url_construction {
    use super::*;
    use netspeed_cli::download::{build_test_url, extract_base_url};
    use netspeed_cli::upload::build_upload_url;

    pub fn bench_build_test_url(c: &mut Criterion) {
        let mut group = c.benchmark_group("url/build_test_url");

        let base = "http://server.example.com/speedtest/upload.php";

        for index in 0..4 {
            group.bench_with_input(
                BenchmarkId::from_parameter(format!("file_{index}")),
                &(base, index),
                |b, &(base, index)| {
                    b.iter(|| {
                        build_test_url(std::hint::black_box(base), std::hint::black_box(index))
                    });
                },
            );
        }

        group.finish();
    }

    pub fn bench_build_upload_url(c: &mut Criterion) {
        c.bench_function("url/build_upload_url", |b| {
            b.iter(|| {
                build_upload_url(std::hint::black_box("http://server.example.com/speedtest"))
            });
        });
    }

    pub fn bench_extract_base_url(c: &mut Criterion) {
        c.bench_function("url/extract_base_url", |b| {
            b.iter(|| {
                extract_base_url(std::hint::black_box(
                    "http://server.example.com/speedtest/upload.php",
                ))
            });
        });
    }
}

criterion_group!(
    benches,
    bandwidth::bench_calculate_bandwidth,
    bandwidth::bench_calculate_bandwidth_zero_elapsed,
    distance::bench_calculate_distance,
    formatting::bench_format_distance,
    formatting::bench_format_data_size,
    validation::bench_is_valid_ipv4,
    url_construction::bench_build_test_url,
    url_construction::bench_build_upload_url,
    url_construction::bench_extract_base_url,
);
criterion_main!(benches);

use clap::CommandFactory;
use clap_complete::{generate_to, Shell};
use std::env;
use std::fs;
use std::path::Path;

// Include CLI args (which pulls in shared validation via its own include!)
include!("src/cli.rs");

fn main() -> std::io::Result<()> {
    // Skip file generation on docs.rs (read-only filesystem)
    if env::var("DOCS_RS").is_ok() {
        return Ok(());
    }

    // Create completions directory
    let out_dir = Path::new("completions");
    fs::create_dir_all(out_dir)?;

    // Generate shell completions
    let mut cmd = Args::command();

    generate_to(Shell::Bash, &mut cmd, "netspeed-cli", out_dir)?;
    generate_to(Shell::Zsh, &mut cmd, "netspeed-cli", out_dir)?;
    generate_to(Shell::Fish, &mut cmd, "netspeed-cli", out_dir)?;
    generate_to(Shell::PowerShell, &mut cmd, "netspeed-cli", out_dir)?;
    generate_to(Shell::Elvish, &mut cmd, "netspeed-cli", out_dir)?;

    // Generate man page
    let man_dir = Path::new(".");
    fs::create_dir_all(man_dir)?;

    let man = clap_mangen::Man::new(cmd);
    let mut buffer: Vec<u8> = Vec::new();
    man.render(&mut buffer)?;

    fs::write(man_dir.join("netspeed-cli.1"), buffer)?;

    println!("cargo:rerun-if-changed=src/cli.rs");
    println!("cargo:rerun-if-changed=Cargo.toml");

    Ok(())
}

// Fuzz tests for security-critical parsing functions
//
// To set up fuzzing:
//   cargo install cargo-fuzz
//   cargo +nightly fuzz init  # Initialize if needed
//   cargo fuzz run xml_parser
//
// This module provides fuzz targets that test:
// - XML parsing (parse_ip_from_xml)
// - Server URL derivation (ServerEndpoints::from_server_url)

use libfuzzer_sys::fuzz_target;
use netspeed_cli::endpoints::ServerEndpoints;
use netspeed_cli::http::parse_ip_from_xml;

/// XML parsing and server URL derivation fuzzer
fuzz_target!(|data: &[u8]| {
    // Convert bytes to string, handling various encodings
    let s = match std::str::from_utf8(data) {
        Ok(s) => s,
        Err(_) => return, // Skip invalid UTF-8
    };

    // Test XML parsing - should be resilient to malformed input
    let _ = parse_ip_from_xml(s);

    // Test server URL parsing - critical for security
    let _ = ServerEndpoints::from_server_url(s);
});

/// IP address in XML context fuzzer
fuzz_target!(|data: &[u8]| {
    let s = match std::str::from_utf8(data) {
        Ok(s) => s,
        Err(_) => return,
    };

    // Test IP address in XML context
    if let Ok(ip) = parse_ip_from_xml(&format!(
        r##'<settings><client ip=“{}”/></settings>'##, s
    )) {
        // If parsing succeeded, verify it's valid
        let _ = ip;
    }
});

//! Shared bandwidth measurement loop for download/upload tests.
//!
//! Eliminates duplication between `download.rs` and `upload.rs` by providing:
//! - [`LoopState`] — unified state for throttled speed sampling,
//!   peak tracking, progress bar updates, and atomic byte counting
//! - [`run_concurrent_streams`] — shared spawn/collect/report pattern
//!   that both download and upload tests delegate to
//!
//! Each I/O operation (download chunk, upload round) calls `record_bytes()`
//! to update shared state. Call `finish()` at the end to compute final results.

use crate::common;
use crate::error::Error;
use crate::progress::Tracker;
use crate::terminal;
use crate::test_config::TestConfig;
use owo_colors::OwoColorize;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;
use std::sync::Mutex;
use std::time::Instant;

/// Throttle interval for speed sampling (20 Hz max).
pub const SAMPLE_INTERVAL_MS: u64 = 50;

/// Shared state for a bandwidth test (download or upload).
///
/// All fields are thread-safe for use across multiple concurrent streams.
pub struct LoopState {
    pub total_bytes: Arc<AtomicU64>,
    pub peak_bps: Arc<AtomicU64>,
    pub speed_samples: Arc<Mutex<Vec<f64>>>,
    pub start: Instant,
    pub last_sample_ms: Arc<AtomicU64>,
    pub estimated_total: u64,
    pub progress: Arc<Tracker>,
}

/// Final result from a bandwidth test.
pub struct BandwidthResult {
    pub avg_bps: f64,
    pub peak_bps: f64,
    pub total_bytes: u64,
    pub duration_secs: f64,
    pub speed_samples: Vec<f64>,
}

impl LoopState {
    /// Create a new bandwidth measurement state.
    #[must_use]
    pub fn new(estimated_total: u64, progress: Arc<Tracker>) -> Self {
        Self {
            total_bytes: Arc::new(AtomicU64::new(0)),
            peak_bps: Arc::new(AtomicU64::new(0)),
            speed_samples: Arc::new(Mutex::new(Vec::new())),
            start: Instant::now(),
            last_sample_ms: Arc::new(AtomicU64::new(0)),
            estimated_total,
            progress,
        }
    }

    /// Record transferred bytes and update progress (throttled to 20 Hz).
    ///
    /// This is the single point where all expensive operations (bandwidth calc,
    /// peak tracking, sample recording, progress update) are throttled.
    ///
    /// Note: Uses cached sample_interval to avoid repeated TestConfig::default() calls.
    pub fn record_bytes(&self, len: u64, sample_interval_ms: u64) {
        // Release ensures writes are visible to the final Acquire load in finish()
        self.total_bytes.fetch_add(len, Ordering::Release);

        let elapsed_ms = u64::try_from(self.start.elapsed().as_millis()).unwrap_or(u64::MAX);
        let last_ms = self.last_sample_ms.load(Ordering::Relaxed);
        let should_sample =
            last_ms == 0 || elapsed_ms.saturating_sub(last_ms) >= sample_interval_ms;

        if should_sample {
            self.last_sample_ms.store(elapsed_ms, Ordering::Relaxed);
            self.sample_now();
        }
    }

    /// Take a speed sample and update progress (no throttle check — caller must gate).
    fn sample_now(&self) {
        let total = self.total_bytes.load(Ordering::Acquire);
        let elapsed = self.start.elapsed().as_secs_f64();
        let speed = common::calculate_bandwidth(total, elapsed);

        // Safe: peak_bps stores bits-per-second; even 100 Gbps = 1e11, well under 2^53.
        let current_peak = self.peak_bps.load(Ordering::Relaxed) as f64;
        if speed > current_peak {
            let peak_u64 = speed.clamp(0.0, u64::MAX as f64) as u64;
            // Release pairs with the Acquire load in finish()
            self.peak_bps.store(peak_u64, Ordering::Release);
        }

        if let Ok(mut samples) = self.speed_samples.lock() {
            samples.push(speed);
        }

        // Safe: total and estimated_total are byte counts from a test lasting seconds;
        // they cannot approach 2^53 (~9 PB) where f64 loses precision.
        let pct = (total as f64 / self.estimated_total as f64).min(1.0);
        self.progress.update(speed / 1_000_000.0, pct, total);
    }

    /// Compute final results from accumulated state.
    #[must_use]
    pub fn finish(&self) -> BandwidthResult {
        // Acquire pairs with the Release fetch_add/stores to see all writes
        let total = self.total_bytes.load(Ordering::Acquire);
        // Safe: peak_bps is bits/sec; even 100 Gbps = 1e11, well under 2^53.
        let peak = self.peak_bps.load(Ordering::Acquire) as f64;
        let duration = self.start.elapsed().as_secs_f64();
        // Graceful fallback: if lock is poisoned (thread panicked), return empty samples
        let samples = self
            .speed_samples
            .lock()
            .map(|g| g.to_vec())
            .unwrap_or_default();
        let avg = common::calculate_bandwidth(total, duration);

        BandwidthResult {
            avg_bps: avg,
            peak_bps: peak,
            total_bytes: total,
            duration_secs: duration,
            speed_samples: samples,
        }
    }
}

/// Run a bandwidth test using multiple concurrent streams.
///
/// This is the shared spawn/collect/report pattern used by both download
/// and upload tests. It:
/// 1. Creates a [`LoopState`] for the test
/// 2. Spawns `stream_count` tasks via `spawn_fn`
/// 3. Collects results, logging any task panics
/// 4. Returns a [`BandwidthResult`] (zeroed if all tasks failed)
///
/// The `spawn_fn` closure receives the stream index and a shared reference
/// to the loop state. Each call should create and return a `JoinHandle<()>`
/// that performs I/O and calls [`LoopState::record_bytes`] for each
/// transferred chunk.
///
/// # Arguments
/// * `estimated_total` — Estimated total bytes for progress bar initialization
/// * `stream_count` — Number of concurrent streams to spawn
/// * `progress` — Shared progress bar for the test phase
/// * `spawn_fn` — Closure that creates one stream's async task
///
/// # Panics
///
/// Individual task panics are caught and logged; they do not propagate.
#[must_use = "the BandwidthResult should be used to report test outcomes"]
pub async fn run_concurrent_streams(
    estimated_total: u64,
    stream_count: usize,
    progress: Arc<Tracker>,
    label: &str,
    mut spawn_fn: impl FnMut(usize, Arc<LoopState>, u64) -> tokio::task::JoinHandle<Result<(), Error>>,
) -> Result<BandwidthResult, Error> {
    let config = TestConfig::default();
    let sample_interval_ms = config.sample_interval_ms;
    let state = Arc::new(LoopState::new(estimated_total, progress));

    let mut handles = Vec::with_capacity(stream_count);
    for i in 0..stream_count {
        handles.push(spawn_fn(i, Arc::clone(&state), sample_interval_ms));
    }

    // Collect results — log any task panics so failures aren't silently swallowed.
    let mut any_succeeded = false;
    let mut first_error: Option<Error> = None;
    for (i, handle) in handles.into_iter().enumerate() {
        match handle.await {
            Ok(Ok(())) => any_succeeded = true,
            Ok(Err(err)) => {
                let msg = format!("Warning: {label} stream {i} failed: {err}");
                if terminal::no_color() {
                    eprintln!("\n{msg}");
                } else {
                    eprintln!("\n{}", msg.yellow().bold());
                }
                if first_error.is_none() {
                    first_error = Some(err);
                }
            }
            Err(e) => {
                let msg = format!("Warning: {label} stream {i} failed: {e}");
                if terminal::no_color() {
                    eprintln!("\n{msg}");
                } else {
                    eprintln!("\n{}", msg.yellow().bold());
                }
                if first_error.is_none() {
                    first_error = Some(Error::context(format!("{label} stream {i} panicked: {e}")));
                }
            }
        }
    }

    if !any_succeeded {
        return Err(
            first_error.unwrap_or_else(|| Error::context(format!("all {label} streams failed")))
        );
    }

    let result = state.finish();
    if result.total_bytes == 0 {
        return Err(first_error.unwrap_or_else(|| match label {
            "download" => {
                Error::DownloadFailure("test completed without transferring data".to_string())
            }
            "upload" => {
                Error::UploadFailure("test completed without transferring data".to_string())
            }
            _ => Error::context(format!("{label} test completed without transferring data")),
        }));
    }

    Ok(result)
}

pub use clap::ArgAction;
use clap::{Parser, ValueEnum};

// Shared validation functions (also used by build.rs via include!)
include!("validate.rs");

#[derive(Parser, Debug)]
#[allow(clippy::struct_excessive_bools)]
#[allow(deprecated)]
#[command(name = "netspeed-cli")]
#[command(version = env!("CARGO_PKG_VERSION"))]
#[command(
    about = "Test internet bandwidth via speedtest.net servers",
    long_about = "Test internet bandwidth via speedtest.net servers.

The default workflow runs a full bandwidth test:
  1. Discover nearest speedtest.net servers
  2. Measure latency (8 ping samples → latency, jitter, packet loss)
  3. Measure download speed (multi-stream, concurrent downloads)
  4. Measure upload speed (multi-stream, concurrent uploads)
  5. Grade results (A+ to F) and show real-world usage estimates

Configuration precedence: CLI flags override config file values, which override built-in defaults.
Results are saved to a local history file for trend tracking."
)]
#[command(
    after_help = "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Examples:
  netspeed-cli                          Run a full speed test
  netspeed-cli --format compact         Key metrics with ratings
  netspeed-cli --format dashboard       Rich dashboard with history
  netspeed-cli --format json            Machine-readable output
  netspeed-cli --list                   List available servers
  netspeed-cli --history                Show test history
  netspeed-cli --profile gamer          Optimize output for gaming
  netspeed-cli --theme light            Light terminal background
  netspeed-cli --no-emoji               Disable emoji output
  netspeed-cli --quiet                  Suppress progress output
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
)]
pub struct Args {
    /// Do not perform download test
    #[arg(long, action = ArgAction::Set, default_missing_value = "true", num_args = 0..=1)]
    pub no_download: Option<bool>,

    /// Do not perform upload test
    #[arg(long, action = ArgAction::Set, default_missing_value = "true", num_args = 0..=1)]
    pub no_upload: Option<bool>,

    /// Only use a single connection instead of multiple
    ///
    /// A single connection measures sustained throughput.
    /// The default uses multiple connections to measure burst/bandwidth capacity.
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Use a single TCP connection for testing (measures sustained throughput).\nThe default uses multiple connections (measures burst/bandwidth capacity)."
    )]
    pub single: Option<bool>,

    /// Display values in bytes instead of bits
    ///
    /// The default displays values in bits (standard for ISP advertising).
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Display values in bytes instead of bits per second.\nThe default uses bits (standard for ISP advertising)."
    )]
    pub bytes: Option<bool>,

    /// Suppress verbose output, only show basic information
    ///
    /// Basic information = one-line summary: latency, download, upload.
    #[deprecated(since = "0.9.0", note = "Use --format simple instead")]
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Suppress verbose output, only show basic information.\nBasic information = one-line summary: latency, download, upload.\nDeprecated: use --format simple instead."
    )]
    pub simple: Option<bool>,

    /// Output in CSV format
    ///
    /// CSV output is suitable for spreadsheet analysis.
    /// Use --csv-header to include column names.
    #[deprecated(since = "0.9.0", note = "Use --format csv instead")]
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Output in CSV format for spreadsheet analysis.\nDeprecated: use --format csv instead."
    )]
    pub csv: Option<bool>,

    /// Single character delimiter for CSV output (default: ",")
    #[arg(long, default_value = ",", value_parser = validate_csv_delimiter)]
    pub csv_delimiter: char,

    /// Print CSV headers
    #[arg(long, action = ArgAction::Set, default_missing_value = "true", num_args = 0..=1)]
    pub csv_header: Option<bool>,

    /// Output in JSON format
    ///
    /// JSON output is machine-readable and includes all measured values.
    #[deprecated(since = "0.9.0", note = "Use --format json instead")]
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Output in JSON format (machine-readable).\nDeprecated: use --format json instead."
    )]
    pub json: Option<bool>,

    /// Output format (supersedes --json, --csv, --simple)
    #[arg(long, value_enum)]
    pub format: Option<OutputFormatType>,

    /// Display a list of speedtest.net servers sorted by distance
    #[arg(
        long,
        long_help = "Display a list of nearby speedtest.net servers sorted by distance.\nDoes not run a bandwidth test."
    )]
    pub list: bool,

    /// Specify a server ID to test against (can be supplied multiple times)
    #[arg(long)]
    pub server: Vec<String>,

    /// Exclude a server from selection (can be supplied multiple times)
    #[arg(long)]
    pub exclude: Vec<String>,

    /// Source IP address to bind to (IPv4 or IPv6)
    #[arg(long, value_parser = validate_ip_address, long_help = "Source IP address to bind to (IPv4 or IPv6).\nUseful on multi-homed systems to select a specific interface.")]
    pub source: Option<String>,

    /// HTTP timeout in seconds (default: 10)
    #[arg(long, default_value = "10", value_parser = validate_timeout)]
    pub timeout: u64,

    /// Generate shell completion script
    #[arg(long, value_enum)]
    pub generate_completion: Option<ShellType>,

    /// Display test history
    #[arg(
        long,
        long_help = "Display test history from the local JSON file.\nDoes not run a bandwidth test."
    )]
    pub history: bool,

    /// Suppress all progress output (JSON/CSV still go to stdout)
    #[arg(
        long,
        action = ArgAction::Set,
        default_missing_value = "true",
        num_args = 0..=1,
        long_help = "Suppress all progress output during the test.\nJSON/CSV output still goes to stdout."
    )]
    pub quiet: Option<bool>,

    /// Validate configuration and exit without running tests
    #[arg(
