// ── Status Computation ───────────────────────────────────────────────────────

/// Compute status for all scenarios given download speed in Mbps.
#[must_use]
pub fn compute_all_statuses(dl_mbps: f64) -> Vec<Vec<ScenarioStatus>> {
    all_categories()
        .iter()
        .map(|cat| {
            cat.scenarios
                .iter()
                .map(|s| {
                    // Safe: dl_mbps/required_mbps is a small ratio; floor→u32 is
                    // bounded by realistic bandwidth values (never approaching u32::MAX).
                    let concurrent = if s.required_mbps > 0.0 {
                        (dl_mbps / s.required_mbps)
                            .floor()
                            .clamp(0.0, f64::from(u32::MAX)) as u32
                    } else {
                        0
                    };
                    let headroom_pct = if s.required_mbps > 0.0 {
                        ((dl_mbps - s.required_mbps) / s.required_mbps * 100.0).max(0.0)
                    } else {
                        100.0
                    };
                    let is_met = dl_mbps >= s.required_mbps;
                    let usage_pct = if TOTAL_BANDWIDTH_MBPS > 0.0 {
                        (s.required_mbps / TOTAL_BANDWIDTH_MBPS) * 100.0
                    } else {
                        0.0
                    };

                    ScenarioStatus {
                        scenario: s,
                        concurrent,
                        headroom_pct,
                        is_met,
                        usage_pct,
                    }
                })
                .collect()
        })
        .collect()
}

//! Dashboard output format V2 — rich single-screen layout with 3-column metrics,
//! compact capability matrix, and two-column estimates.
//!
//! Layout priority:
//! 1. Header: Server + IP + version (rounded box)
//! 2. Metrics dashboard: Performance | Stability | Bufferbloat (3 columns)
//! 3. Capability matrix: compact table with warnings-only
//! 4. Transfer estimates: two-column layout
//! 5. Footer: Grade + timestamp

#![allow(
    clippy::cast_precision_loss,
    clippy::cast_possible_truncation,
    clippy::cast_sign_loss
)]

