///
/// # Errors
///
/// This function does not currently return errors, but the signature is
/// `Result` for future extensibility.
pub fn format_list(servers: &[Server]) -> Result<(), std::io::Error> {
    eprintln!("{}", build_list(servers));
    Ok(())
}

//! Speed stability analysis and latency percentiles.

#![allow(
    clippy::cast_precision_loss,
    clippy::cast_possible_truncation,
    clippy::cast_sign_loss
)]

use crate::theme::{Colors, Theme};

/// Compute coefficient of variation (CV) as a percentage.
#[must_use]
pub fn compute_cv(speeds: &[f64]) -> f64 {
    if speeds.is_empty() {
        return 0.0;
    }
    // Safe: sample counts are small (≤1000), well under 2^53.
    let n = speeds.len() as f64;
    let mean = speeds.iter().sum::<f64>() / n;
    if mean <= 0.0 {
        return 0.0;
    }
    let variance = speeds.iter().map(|s| (s - mean).powi(2)).sum::<f64>() / n;
    let stddev = variance.sqrt();
    (stddev / mean) * 100.0
}

#[must_use]
pub fn format_stability_line(cv: f64, nc: bool, theme: Theme) -> String {
    let label = if cv < 5.0 {
        "rock-solid"
    } else if cv < 10.0 {
        "very stable"
    } else if cv < 20.0 {
        "moderate"
    } else if cv < 35.0 {
        "variable"
    } else {
        "unstable"
    };
    let text = format!("±{cv:.0}% {label}");
    if nc {
        text
    } else if cv < 5.0 {
        Colors::good(&text, theme)
    } else if cv < 20.0 {
        Colors::warn(&text, theme)
    } else {
        Colors::bad(&text, theme)
    }
}

#[must_use]
pub fn compute_percentiles(samples: &[f64]) -> Option<(f64, f64, f64)> {
    let n = samples.len();
    if n < 3 {
        return None;
    }
    let mut data = samples.to_vec();
    let p50_idx = n * 50 / 100;
    let p95_idx = (n * 95 / 100).min(n - 1);
    let p99_idx = (n * 99 / 100).min(n - 1);

    // Partition at p99: elements before are <= p99, elements after are >= p99
    data.select_nth_unstable_by(p99_idx, |a, b| {
        a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal)
    });
    let p99 = data[p99_idx];

    // Partition the left slice at p95
    data.select_nth_unstable_by(p95_idx, |a, b| {
        a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal)
    });
    let p95 = data[p95_idx];

    // Partition the left slice at p50
    data.select_nth_unstable_by(p50_idx, |a, b| {
        a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal)
    });
    let p50 = data[p50_idx];

    Some((p50, p95, p99))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_compute_cv_constant() {
        let speeds = vec![100.0, 100.0, 100.0];
        assert!(compute_cv(&speeds).abs() < f64::EPSILON);
    }

    #[test]
    fn test_compute_cv_empty() {
        assert!(compute_cv(&[]).abs() < f64::EPSILON);
    }

    #[test]
    fn test_compute_percentiles_basic() {
        let samples: Vec<f64> = (1..=100).map(f64::from).collect();
        let result = compute_percentiles(&samples);
        assert!(result.is_some());
        let (p50, p95, p99) = result.unwrap();
        // With 100 elements (indices 0..99), n*50/100 = 50 → index 50 → value 51.0
        assert!((p50 - 51.0).abs() < 1.0);
        assert!((p95 - 96.0).abs() < 1.0);
        assert!((p99 - 100.0).abs() < 1.0);
    }

    #[test]
    fn test_compute_percentiles_too_few() {
        assert!(compute_percentiles(&[1.0, 2.0]).is_none());
    }
}

//! Comprehensive quality grade system (A-F) for all connection metrics.
//!
//! Provides letter grades with color support for:
//! - Ping/Latency
//! - Jitter
//! - Download speed
//! - Upload speed
//! - Bufferbloat
//! - Stability (CV%)
//! - Overall connection quality

use crate::profiles::UserProfile;
use crate::terminal;
use crate::theme::{Colors, Theme};

/// Letter grade for connection quality.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum LetterGrade {
    APlus,
    A,
    AMinus,
    BPlus,
    B,
    BMinus,
    CPlus,
    C,
    CMinus,
    D,
    F,
}

impl LetterGrade {
    /// Display string for the grade.
    #[must_use]
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::APlus => "A+",
            Self::A => "A",
            Self::AMinus => "A-",
            Self::BPlus => "B+",
            Self::B => "B",
            Self::BMinus => "B-",
            Self::CPlus => "C+",
            Self::C => "C",
            Self::CMinus => "C-",
            Self::D => "D",
            Self::F => "F",
        }
    }

    /// Color for the grade (green = good, red = bad).
    #[must_use]
    pub fn color_str(&self, nc: bool, theme: Theme) -> String {
        let s = self.as_str();
        if nc {
            return format!("[{s}]");
        }
        match self {
            Self::APlus | Self::A | Self::AMinus | Self::BPlus | Self::B => Colors::good(s, theme),
            Self::BMinus | Self::CPlus | Self::C | Self::CMinus | Self::D => Colors::warn(s, theme),
            Self::F => Colors::bad(s, theme),
        }
    }

    /// Emoji indicator for the grade.
    #[must_use]
    pub fn emoji(&self) -> &'static str {
        if terminal::no_emoji() {
            return "";
        }
        match self {
            Self::APlus | Self::A | Self::AMinus => "⚡",
            Self::BPlus | Self::B => "✅",
            Self::BMinus | Self::CPlus | Self::C => "⚠️",
            Self::CMinus | Self::D => "❌",
            Self::F => "🚫",
        }
    }

    /// Numeric score 0-100 for the grade.
    #[must_use]
    pub fn score(&self) -> f64 {
        match self {
            Self::APlus => 100.0,
            Self::A => 95.0,
            Self::AMinus => 90.0,
            Self::BPlus => 85.0,
            Self::B => 80.0,
            Self::BMinus => 75.0,
            Self::CPlus => 70.0,
            Self::C => 65.0,
            Self::CMinus => 60.0,
            Self::D => 50.0,
            Self::F => 25.0,
        }
    }

    /// Human-readable description.
    #[must_use]
    pub fn description(&self) -> &'static str {
        match self {
            Self::APlus => "Exceptional",
            Self::A => "Excellent",
            Self::AMinus => "Very Good",
            Self::BPlus => "Good+",
            Self::B => "Good",
            Self::BMinus => "Above Average",
            Self::CPlus => "Average+",
            Self::C => "Average",
            Self::CMinus => "Below Average",
            Self::D => "Poor",
            Self::F => "Unacceptable",
        }
    }
}

/// Grade a ping value (lower is better).
/// Profile-aware thresholds.
#[must_use]
pub fn grade_ping(ping_ms: f64, profile: UserProfile) -> LetterGrade {
    let excellent = profile.excellent_ping_threshold();
    let good = excellent * 3.0;
    let average = excellent * 6.0;

    if ping_ms <= excellent * 0.5 {
        LetterGrade::APlus
    } else if ping_ms <= excellent {
        LetterGrade::A
    } else if ping_ms <= excellent * 1.5 {
        LetterGrade::AMinus
    } else if ping_ms <= good {
        LetterGrade::B
    } else if ping_ms <= good * 1.5 {
        LetterGrade::C
    } else if ping_ms <= average {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Grade jitter value (lower is better).
#[must_use]
pub fn grade_jitter(jitter_ms: f64, profile: UserProfile) -> LetterGrade {
    let excellent = profile.excellent_jitter_threshold();
    let good = excellent * 3.0;
    let average = excellent * 8.0;

    if jitter_ms <= excellent * 0.5 {
        LetterGrade::APlus
    } else if jitter_ms <= excellent {
        LetterGrade::A
    } else if jitter_ms <= excellent * 2.0 {
        LetterGrade::B
    } else if jitter_ms <= good {
        LetterGrade::C
    } else if jitter_ms <= average {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Grade download speed (higher is better).
#[must_use]
pub fn grade_download(speed_mbps: f64, profile: UserProfile) -> LetterGrade {
    let excellent = profile.excellent_speed_threshold();
    let good = excellent * 0.4;
    let average = excellent * 0.15;

    if speed_mbps >= excellent * 2.0 {
        LetterGrade::APlus
    } else if speed_mbps >= excellent {
        LetterGrade::A
    } else if speed_mbps >= excellent * 0.75 {
        LetterGrade::B
    } else if speed_mbps >= good {
        LetterGrade::C
    } else if speed_mbps >= average {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Grade upload speed (higher is better).
#[must_use]
pub fn grade_upload(speed_mbps: f64, profile: UserProfile) -> LetterGrade {
    // Upload thresholds are typically 50% of download
    let excellent = profile.excellent_speed_threshold() * 0.5;
    let good = excellent * 0.4;
    let average = excellent * 0.15;

    if speed_mbps >= excellent * 2.0 {
        LetterGrade::APlus
    } else if speed_mbps >= excellent {
        LetterGrade::A
    } else if speed_mbps >= excellent * 0.75 {
        LetterGrade::B
    } else if speed_mbps >= good {
        LetterGrade::C
    } else if speed_mbps >= average {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Grade bufferbloat based on added latency under load.
#[must_use]
pub fn grade_bufferbloat(added_latency_ms: f64) -> LetterGrade {
    if added_latency_ms < 3.0 {
        LetterGrade::APlus
    } else if added_latency_ms < 5.0 {
        LetterGrade::A
    } else if added_latency_ms < 10.0 {
        LetterGrade::AMinus
    } else if added_latency_ms < 20.0 {
        LetterGrade::BPlus
    } else if added_latency_ms < 30.0 {
        LetterGrade::B
    } else if added_latency_ms < 50.0 {
        LetterGrade::C
    } else if added_latency_ms < 100.0 {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Grade stability based on CV% (lower = more stable).
#[must_use]
pub fn grade_stability(cv_pct: f64) -> LetterGrade {
    if cv_pct < 3.0 {
        LetterGrade::APlus
    } else if cv_pct < 5.0 {
        LetterGrade::A
    } else if cv_pct < 8.0 {
        LetterGrade::B
    } else if cv_pct < 15.0 {
        LetterGrade::C
    } else if cv_pct < 25.0 {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Compute overall connection grade from individual grades and profile weights.
#[must_use]
pub fn grade_overall(
    ping: Option<f64>,
    jitter: Option<f64>,
    download_bps: Option<f64>,
    upload_bps: Option<f64>,
    profile: UserProfile,
) -> LetterGrade {
    let (ping_w, jitter_w, dl_w, ul_w) = profile.scoring_weights();
    let mut total_score = 0.0;
    let mut total_weight = 0.0;

    if let Some(p) = ping {
        total_score += grade_ping(p, profile).score() * ping_w;
        total_weight += ping_w;
    }
    if let Some(j) = jitter {
        total_score += grade_jitter(j, profile).score() * jitter_w;
        total_weight += jitter_w;
    }
    if let Some(dl) = download_bps {
        total_score += grade_download(dl / 1_000_000.0, profile).score() * dl_w;
        total_weight += dl_w;
    }
    if let Some(ul) = upload_bps {
        total_score += grade_upload(ul / 1_000_000.0, profile).score() * ul_w;
        total_weight += ul_w;
    }

    if total_weight == 0.0 {
        return LetterGrade::F;
    }

    let avg_score = total_score / total_weight;
    score_to_grade(avg_score)
}

/// Convert a numeric score (0-100) to a letter grade.
#[must_use]
pub fn score_to_grade(score: f64) -> LetterGrade {
    if score >= 97.0 {
        LetterGrade::APlus
    } else if score >= 93.0 {
        LetterGrade::A
    } else if score >= 90.0 {
        LetterGrade::AMinus
    } else if score >= 87.0 {
        LetterGrade::BPlus
    } else if score >= 80.0 {
        LetterGrade::B
    } else if score >= 77.0 {
        LetterGrade::BMinus
    } else if score >= 70.0 {
        LetterGrade::CPlus
    } else if score >= 65.0 {
        LetterGrade::C
    } else if score >= 60.0 {
        LetterGrade::CMinus
    } else if score >= 50.0 {
        LetterGrade::D
    } else {
        LetterGrade::F
    }
}

/// Format a grade line with label, grade, and optional value.
#[must_use]
pub fn format_grade_line(
    label: &str,
    grade: LetterGrade,
    value: Option<&str>,
    nc: bool,
    theme: Theme,
) -> String {
    let emoji = grade.emoji();
    let grade_display = grade.color_str(nc, theme);
    let value_str = value.map(|v| format!(" ({v})")).unwrap_or_default();

    if nc || terminal::no_emoji() {
        format!("  {label:>14}:   {grade_display}{value_str}")
    } else {
        format!("  {label:>14}:   {emoji} {grade_display}{value_str}")
    }
}

#[must_use]
pub fn grade_badge(grade: LetterGrade, nc: bool, theme: Theme) -> String {
    let emoji = grade.emoji();
    let grade_display = grade.color_str(nc, theme);
    if nc {
        format!("[{grade_display}]")
    } else if terminal::no_emoji() {
        grade_display.clone()
    } else {
        format!("{emoji} {grade_display}")
    }
}

